import { Registry } from '../../core/zc-registry';
import { each } from '../../utils/zcutils';

export function tangentPoints$Polygon(polygonPoints, isHorizontal, position = [{ x: 0, y: 0 }, { x: 0, y: 0 }]) {
    //TODO: ninja|clover|butterfly
    //TODO: Overlapping polygons
    //http://geomalgorithms.com/a15-_tangents.html
    //https://arxiv.org/pdf/1601.01816.pdf
    //https://www.geeksforgeeks.org/tangents-two-convex-polygons/?ref=rp

    let tangent = polygonPoints.map((points, i) => {
        let q1, q2, q3, q4;
        each(points, p => {
            if (isHorizontal) {
                if (p[0] < 0 && p[1] < 0) {
                    if (!q1 || q1[1] > p[1]) {
                        q1 = p;
                    }
                } else if (p[0] >= 0 && p[1] < 0) {
                    if (!q2 || q2[1] > p[1]) {
                        q2 = p;
                    }
                } else if (p[0] >= 0 && p[1] >= 0) {
                    if (!q3 || q3[1] < p[1]) {
                        q3 = p;
                    }
                } else {
                    if (!q4 || q4[1] < p[1]) {
                        q4 = p;
                    }
                }
            } else {
                if (p[0] < 0 && p[1] < 0) {
                    if (!q1 || q1[0] > p[0]) {
                        q1 = p;
                    }
                } else if (p[0] >= 0 && p[1] < 0) {
                    if (!q2 || q2[0] < p[0]) {
                        q2 = p;
                    }
                } else if (p[0] >= 0 && p[1] >= 0) {
                    if (!q3 || q3[0] < p[0]) {
                        q3 = p;
                    }
                } else {
                    if (!q4 || q4[0] > p[0]) {
                        q4 = p;
                    }
                }
            }
        });

        let point = isHorizontal ? (i == 0 ? [q2, q3] : [q1, q4]) : i == 0 ? [q3, q4] : [q2, q1];
        each(point, d => {
            if (d) {
                d[0] += position[i].x;
                d[1] += position[i].y;
            }
        });

        return point;
    });

    return [tangent[0][0], tangent[1][0], tangent[0][1], tangent[1][1]];
}

Registry.setComponent('geometryUtils.polygon.outerTangentPoints', tangentPoints$Polygon);
